   150→  absl::optional<chttp2::TransportFlowControl::Stats> transport_stats_;
   151→  absl::optional<chttp2::StreamFlowControl::Stats> stream_stats_;
   152→  absl::optional<WriteStats> write_stats_;
   153→};
